import React, { useState } from 'react';
import axios from 'axios';
import './AddCarnetModal.css';

const API_URL = process.env.REACT_APP_API_URL || 'http://localhost:5000';

function AddCarnetModal({ isOpen, onClose, onCarnetAdded, token, usuarioId }) {
  const [form, setForm] = useState({
    nombre_completo: '',
    cedula: '',
    cargo: '',
  });
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [success, setSuccess] = useState('');

  const handleChange = (e) => {
    const { name, value } = e.target;
    setForm((prev) => ({ ...prev, [name]: value }));
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError('');
    setSuccess('');
    setLoading(true);

    try {
      const response = await axios.post(
        `${API_URL}/api/carnets/agregar-empleado`,
        {
          nombre_completo: form.nombre_completo,
          cedula: form.cedula,
          usuario_id: usuarioId,
        },
        {
          headers: { Authorization: `Bearer ${token}` },
        }
      );

      setSuccess('Carnet de empleado agregado exitosamente');
      setForm({ nombre_completo: '', cedula: '' });

      setTimeout(() => {
        onCarnetAdded();
        onClose();
      }, 1500);
    } catch (err) {
      setError(err.response?.data?.message || 'Error al agregar carnet');
    } finally {
      setLoading(false);
    }
  };

  if (!isOpen) return null;

  return (
    <div className="modal-overlay" onClick={onClose}>
      <div className="modal-content" onClick={(e) => e.stopPropagation()}>
        <div className="modal-header">
          <h2>Agregar Carnet de Empleado</h2>
          <button className="modal-close" onClick={onClose}>×</button>
        </div>

        <form onSubmit={handleSubmit} className="modal-form">
          {error && <div className="modal-error">{error}</div>}
          {success && <div className="modal-success">{success}</div>}

          <div className="modal-field">
            <label htmlFor="nombre_completo">Nombre Completo</label>
            <input
              id="nombre_completo"
              name="nombre_completo"
              type="text"
              value={form.nombre_completo}
              onChange={handleChange}
              placeholder="Juan Pérez"
              required
            />
          </div>

          <div className="modal-field">
            <label htmlFor="cedula">Cédula</label>
            <input
              id="cedula"
              name="cedula"
              type="text"
              value={form.cedula}
              onChange={handleChange}
              placeholder="1131110580"
              required
            />
          </div>

          <div className="modal-actions">
            <button type="button" className="btn-cancel" onClick={onClose}>
              Cancelar
            </button>
            <button type="submit" className="btn-submit" disabled={loading}>
              {loading ? 'Agregando...' : 'Agregar Carnet'}
            </button>
          </div>
        </form>
      </div>
    </div>
  );
}

export default AddCarnetModal;
